SELECT size_category, COUNT(size_id) AS num_sizes
FROM sizes
GROUP BY size_category;

SELECT market, COUNT(*) AS number_of_reports
FROM size_reports
GROUP BY market;

SELECT size_label, size_description, size_category
FROM sizes
WHERE size_id = 1;

SELECT AVG(trend_value) AS average_trend_value
FROM size_trends
WHERE trend_date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT SUM(units_sold) 
FROM size_reports 
WHERE size_id = 1 AND market = 'Europe';
